insert into tbl_journal_form (
	form_id,	tenant_id,		form_name,		form_content,		type_id,		form_date,		form_writer,		form_info,		company_id
)
values (
	#formId#,	#tenantId#,		#formName#,		#formContent#,		#typeId#,		now(),			#formWriter#,		#formInfo#,		#companyId#
)

insert into tbl_journal_form_user_dept (
	dept_id,	form_id
)
values (
	#deptId#,	#formId#
)
